The `debounce` function is a utility that prevents a function from being called too many times in a short period of time by delaying its execution until a specified amount of time has passed since the last call.

```javascript
function debounce(callback, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => callback(...args), delay);
  }
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
debouncedLog("Hello"); // Will be logged after 500ms
debouncedLog("World"); // Previous log is cancelled, "World" will be logged after 500ms
```
